// Recognize overflow check for unsigned addition: (add A, B) <u A  or  A >u (add A, B)
// These two forms are equivalent; also the check with B is equivalent to that with A.
// Thus, (overflow check with A) | (overflow check with B) -> overflow check with A.
// Similarly for &, and also for ULE/UGE.
auto getUAddOverflowCheck = [&](ICmpInst *Cmp, Value *&Add, Value *&Other) -> bool {
  ICmpInst::Predicate Pred = Cmp->getPredicate();
  Value *Op0 = Cmp->getOperand(0), *Op1 = Cmp->getOperand(1);
  // (add A, B) < A  -> ULT/ULE
  // A > (add A, B)  -> UGT/UGE
  if (Pred == ICmpInst::ICMP_ULT || Pred == ICmpInst::ICMP_ULE) {
    if (match(Op0, m_Add(m_Value(), m_Value()))) {
      Add = Op0;
      Other = Op1;
      return true;
    }
  } else if (Pred == ICmpInst::ICMP_UGT || Pred == ICmpInst::ICMP_UGE) {
    if (match(Op1, m_Add(m_Value(), m_Value()))) {
      Add = Op1;
      Other = Op0;
      return true;
    }
  }
  return false;
};

Value *AddL = nullptr, *OtherL = nullptr;
Value *AddR = nullptr, *OtherR = nullptr;
if (getUAddOverflowCheck(LHS, AddL, OtherL) &&
    getUAddOverflowCheck(RHS, AddR, OtherR) &&
    AddL == AddR) {
  // Ensure that OtherL and OtherR are operands of the add.
