  Value *AddOp0 = cast<BinaryOperator>(AddL)->getOperand(0);
  Value *AddOp1 = cast<BinaryOperator>(AddL)->getOperand(1);
  if ((OtherL == AddOp0 || OtherL == AddOp1) &&
      (OtherR == AddOp0 || OtherR == AddOp1)) {
    // The two comparisons are equivalent (both check overflow of same add).
    // Return either one.
    return LHS;
  }

