@@ -3093,8 +3093,49 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
     }
   }

-  // handle (roughly):
-  // (icmp ne (A & B), C) | (icmp ne (A & D), E)
+  // Recognize overflow check for unsigned addition: (add A, B) <u A  or  A >u (add A, B)
+  // These two forms are equivalent; also the check with B is equivalent to that with A.
+  // Thus, (overflow check with A) | (overflow check with B) -> overflow check with A.
+  // Similarly for &, and also for ULE/UGE.
+  auto getUAddCheck = [&](ICmpInst *Cmp, Value *&Add, Value *&Other, bool &IsOverflow) -> bool {
+    ICmpInst::Predicate Pred = Cmp->getPredicate();
+    Value *Op0 = Cmp->getOperand(0), *Op1 = Cmp->getOperand(1);
+    // Check if Op0 is add.
+    if (match(Op0, m_Add(m_Value(), m_Value()))) {
+      Add = Op0;
+      Other = Op1;
+      // (add) <  Other -> overflow; (add) >= Other -> no-overflow
+      IsOverflow = (Pred == ICmpInst::ICMP_ULT || Pred == ICmpInst::ICMP_ULE);
+      return IsOverflow || (Pred == ICmpInst::ICMP_UGT || Pred == ICmpInst::ICMP_UGE);
+    }
+    // Check if Op1 is add.
+    if (match(Op1, m_Add(m_Value(), m_Value()))) {
+      Add = Op1;
+      Other = Op0;
+      // Other > (add) -> overflow; Other <= (add) -> no-overflow
+      IsOverflow = (Pred == ICmpInst::ICMP_UGT || Pred == ICmpInst::ICMP_UGE);
+      return IsOverflow || (Pred == ICmpInst::ICMP_ULT || Pred == ICmpInst::ICMP_ULE);
+    }
+    return false;
+  };
+
+  Value *AddL = nullptr, *OtherL = nullptr;
+  bool OverflowL = false;
+  Value *AddR = nullptr, *OtherR = nullptr;
+  bool OverflowR = false;
+  if (getUAddCheck(LHS, AddL, OtherL, OverflowL) &&
+      getUAddCheck(RHS, AddR, OtherR, OverflowR) &&
+      AddL == AddR && OverflowL == OverflowR) {
+    // Ensure that OtherL and OtherR are operands of the add.
+    Value *AddOp0 = cast<BinaryOperator>(AddL)->getOperand(0);
+    Value *AddOp1 = cast<BinaryOperator>(AddL)->getOperand(1);
+    if ((OtherL == AddOp0 || OtherL == AddOp1) &&
+        (OtherR == AddOp0 || OtherR == AddOp1)) {
+      // The two comparisons are equivalent (both check overflow of same add).
+      // Return either one.
+      return LHS;
+    }
+  }
   // (icmp eq (A & B), C) & (icmp eq (A & D), E)
   if (Value *V = foldLogOpOfMaskedICmps(LHS, RHS, IsAnd, IsLogical, Builder))
     return V;
